import{_ as s,o as n,c as t,O as l}from"./chunks/framework.47655c42.js";const m=JSON.parse('{"title":"","description":"","frontmatter":{"aside":false,"outline":false,"lastUpdated":false},"headers":[],"relativePath":"materials/value.md","filePath":"materials/value.md","lastUpdated":1775907908000}'),r={name:"materials/value.md"};function e(p,a,i,c,d,_){return n(),t("div",null,a[0]||(a[0]=[l('<div class="brand-page-shell"><section class="brand-hero"><div><p class="brand-kicker">Value Narrative</p><h1>价值说明</h1><div class="brand-hero__panel"><span class="brand-pill">Decision Layer</span><strong>客户最终不会为“有个 AI 页面”买单，而会为效率、可控性和眼前能不能解决问题买单。</strong><p>价值判断的重点通常集中在效率、可控性和当前是否值得启动试点。</p></div><p class="brand-lead"> 价值判断通常集中在决策者最常问的三个问题： <strong>它到底省什么事、它到底安不安全、它到底值不值得现在拿一个真实场景试起来。</strong> 如果产品能在这三件事上讲不清，后面的技术细节就很难继续推进。 </p><div class="brand-chip-list"><span class="brand-chip">效率</span><span class="brand-chip">可控性</span><span class="brand-chip">可交付性</span><span class="brand-chip">是否值得先试</span></div><div class="brand-actions"><a class="cta-button cta-button--brand" href="./pitch.html">看介绍提纲</a><a class="cta-button" href="../product/customer-flow.html">看客户流程 / 交付</a></div></div><div class="brand-hero__media brand-hero__media--compact"><div class="matrix-panel matrix-panel--contact"><div class="matrix-panel__hud"><span>EXECGOV // VALUE NARRATIVE</span><span>MAT 03</span></div><div class="matrix-panel__canvas"><div class="matrix-panel__trace matrix-panel__trace--top"></div><div class="matrix-panel__trace matrix-panel__trace--mid"></div><div class="matrix-panel__trace matrix-panel__trace--bottom"></div><div class="matrix-panel__stack"><span class="matrix-panel__line"><span class="matrix-panel__key">save</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">manual_steps</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__ident">repeated_handoff</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">control</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__string">permission</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__fn">confirm</span><span class="matrix-panel__sep"> / </span><span class="matrix-panel__value matrix-panel__fn">audit_trail</span></span><span class="matrix-panel__line"><span class="matrix-panel__key">grow</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value matrix-panel__ident">reusable_delivery_base</span></span></div><div class="matrix-panel__callout">VALUE = COST / SPEED / RISK</div></div><div class="matrix-panel__footer"><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">efficiency</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">control</span></span><span class="matrix-panel__tag"><span class="matrix-panel__key">focus</span><span class="matrix-panel__punct">:</span> <span class="matrix-panel__value">growth</span></span></div></div></div></section><section class="brand-grid brand-grid--three"><article class="brand-card"><p class="brand-kicker">Question 01</p><h2>它到底帮我省什么事</h2><p>它把原本分散在命令、脚本、接口、模板、文件夹和人工经验里的执行能力，收成统一入口，减少重复劳动、找能力时间和跨人沟通成本。</p></article><article class="brand-card"><p class="brand-kicker">Question 02</p><h2>它到底安不安全、可不可控</h2><p>平台强调权限边界、人工确认、执行留痕和租户隔离，不会让 AI 在系统里脱离规则自由执行。</p></article><article class="brand-card"><p class="brand-kicker">Question 03</p><h2>它到底值不值得现在就试</h2><p>已有脚本、接口、报表处理或本地流程时，这套平台可以先把最痛的一段接进统一入口，再判断是否要继续扩展。</p></article></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">Efficiency</p><h2>为什么它能省事</h2><ul class="brand-list"><li>不再靠人记脚本路径和命令</li><li>不再靠少数人临时口口相传</li><li>同一类工作可以通过统一入口反复执行</li><li>AI 可以把“找能力”这一步做得更自然</li></ul></article><article class="brand-card"><p class="brand-kicker">Control</p><h2>为什么它不是“让 AI 在系统里自由运行”</h2><ul class="brand-list"><li>推荐范围受租户和权限约束</li><li>高风险动作可要求人工确认</li><li>执行结果和记录可以追踪</li><li>客户之间默认隔离，不互相可见</li></ul></article></section><section class="brand-card"><p class="brand-kicker">Decision View</p><h2>不同角色通常关心什么</h2><table><thead><tr><th>角色</th><th>最关心的问题</th><th>建议怎么讲</th><th>继续阅读</th></tr></thead><tbody><tr><td>老板 / 决策者</td><td>值不值得投、能不能形成长期资产</td><td>强调效率提升、可控执行、后续扩展空间</td><td><a href="./pitch.html">介绍提纲</a></td></tr><tr><td>业务负责人</td><td>能不能真正把现有流程接入平台</td><td>强调统一入口、AI 推荐、结果回显和热更新</td><td><a href="../product/customer-flow.html">客户流程 / 交付</a></td></tr><tr><td>技术负责人</td><td>可不可控、会不会串租户、能不能持续交付</td><td>强调租户隔离、权限边界、审核与授权、CLI 桥梁能力</td><td><a href="../product/architecture.html">架构说明</a></td></tr><tr><td>交付负责人</td><td>上线后怎么继续更新和验收</td><td>强调客户流程、交付清单、热更新和验收重点</td><td><a href="../product/customer-flow.html">客户流程 / 交付</a></td></tr></tbody></table></section><section class="brand-grid brand-grid--two"><article class="brand-card"><p class="brand-kicker">One Sentence</p><h2>一句话怎么讲价值</h2><p>ExecGov 不是再造一个聊天框，而是帮你把团队里那些散装的、危险的脚本和自动化流程收成统一入口，让它们跑得稳、留得下、查得到。</p></article><article class="brand-card"><p class="brand-kicker">Longer Version</p><h2>一段话怎么讲价值</h2><p>很多企业并不缺脚本、接口、模板和流程，真正缺的是统一入口、权限边界和可持续交付能力。ExecGov 的价值，在于把这些分散能力收进一个可控执行平台，让客户通过统一入口使用自己的能力，让平台在边界内完成推荐、确认、执行和留痕。当前最成熟的第一种执行资产仍然是 Python 脚本，但平台现在更重要的任务不是讲一个很大的故事，而是先把这些能力单元稳定接入真实项目。</p></article></section><section class="brand-card brand-card--cta"><div class="brand-card__row"><div><p class="brand-kicker">Next Read</p><h2>价值判断之后，需要继续看交付事实</h2><p class="brand-lead">价值表达如果不能接到真实交付路径上，项目判断通常不会继续往下走。</p></div><div class="brand-link-grid brand-link-grid--compact"><a class="brand-link-card" href="../product/customer-flow.html"><span>Delivery</span><strong>客户流程 / 交付</strong></a><a class="brand-link-card" href="../product/deployment.html"><span>Deployment</span><strong>部署方式</strong></a><a class="brand-link-card" href="../product/editions.html"><span>Roadmap</span><strong>版本路线</strong></a><a class="brand-link-card" href="../contact.html#lead-form"><span>Lead</span><strong>沟通真实场景</strong></a></div></div></section></div>',1)]))}const h=s(r,[["render",e]]);export{m as __pageData,h as default};
